-- W1.6 questions batch 2149/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-adfe9b2d-moex-00008', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-13504c0c', 'sub-diplomatic-adfe9b2d-01', NULL, 'single_choice', '「大部分人的語言能力主要由左半腦負責。語言產生和布氏區（Broca’sarea）有關， 語言理解和威氏區（Wernicke’s area）有關，這兩個區域之間藉由弓形束（arcuate fasciculus）獲得聯繫。語言學習具有關鍵期，但學習第二語言並非越早越好！語言 學習占用大腦資源和時間，除非在兩種語言都有豐富學習機會的雙語環境下，否則 應該到認知功能與大腦發展差不多後，懂得運用學習的策略和技巧，再來學第二語 言會更恰當！」 根據上文，下列選項何者最符合文意？', '["人類的語言功能完全由左半腦中的布氏區、威氏區負責", "布氏區處理語言理解，威氏區與語言產生有關，弓形束聯繫兩者", "學習者如無雙語環境，最好等大腦認知功能較成熟後，再學習第二語言", "語言學習具有關鍵期，三歲之後發音方法固定，因此學習第二語言越早越好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00009', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-13504c0c', 'sub-diplomatic-adfe9b2d-01', NULL, 'single_choice', '「法語的松鼠毛（Vair）音同於玻璃（Verre）。在十七世紀，蘇格蘭、愛爾蘭、加泰 隆尼亞（在今西班牙）一帶，玻璃是罕見且珍貴的，於是，一六九七年法國作家夏 爾．佩羅（CharlesPerrault）在記述灰姑娘故事時便訛誤（或改編？）為玻璃鞋了。 人們都愛童話故事，因為真正的生活總是那樣的蒼白與無奈，在故事中尋找一個浪 漫美好的夢，即使明知是虛假的，我們都享受那樣被矇迷的片刻啊！」 根據上文，下列選項最符合文意的是：', '["日常生活中，我們常常運用音同，而創造出許多新鮮的詞彙", "許多習以為常的事物，若從語源上追溯可以發覺不同的面貌", "大部分的人都喜歡童話故事，因可以陶醉在浪漫愛情的時光", "灰姑娘的童話故事，玻璃鞋的使用有誤，造成內容蒼白無奈"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00010', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-13504c0c', 'sub-diplomatic-adfe9b2d-01', NULL, 'single_choice', '「身為偉大的候鳥族群，我們是活在北方凍土帶的環頸鴴……皮諾查下意識裡一直 認為，這些不肯回去的環頸鴴，已嚴重地觸犯祖先的規範，他們的行徑全然是他種 留鳥的習性，汙蔑了所有環頸鴴。但環頸鴴是和平的鳥類，縱使犯了這麼大的忤逆 罪，他們仍尊重這些『留鳥』的選擇。不過，部族的長老們憂心地意識到，這是明 顯的退化；他們若不繼續維持兩地來去的傳統，環頸鴴將無法和其他同型的鴴鷸科 水鳥競爭，未來有可能導致滅族的危機。過去，受到傳統教育的訓示，回到北方的 環頸鴴們也恥於談留鳥環頸鴴的問題。雖然他們在南方經常與留鳥一起相處，候鳥 們甚少細心探究過留鳥的形成原由。久而久之，每到春天後，就有一群留鳥滯留南 方，繁衍下一代。他們形成另一種傳統，對候鳥的遷徙反而覺得不可思議。」 有關上文形式與內涵，下列敘述何者正確？', '["文中具體展現了人類與動物的互動", "強調人類對「自然」已然造成某些改變與影響的事實", "作者在環頸鴴的行為與習性的基礎上賦予其「人格」，藉此揣測候鳥、留鳥之謎", "上文主旨在於藉由鳥類的視角演繹人類的價值觀，並非帶領讀者理解環頸鴴的 生態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00011', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-e6f33b51', 'sub-diplomatic-adfe9b2d-02', NULL, 'essay', '美國川普總統於2025 年 4月對各國推出對等關稅。請回答下列問題：
美國的對等關稅稅率是否即為貿易理論中的最適關稅稅率？若為不
同，請詳細說明兩者各自如何訂定，以及其背後的目的各自為何？（請
注意在說明最適關稅稅率時，請以從量稅為例，並繪圖且輔以貿易理
論中相關的專有名詞）（15 分）
為抵制美國對等關稅，某國擬對美國商品課以報復性關稅。在排除世
界貿易組織（WorldTradeOrganization,WTO）相關規定等法律性和政
治性考量的情況下，請以經濟學理和實務的觀點評論之。（請至少提出
兩個觀點）（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00012', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-e6f33b51', 'sub-diplomatic-adfe9b2d-02', NULL, 'essay', '區域貿易協定在世界貿易組織（World Trade Organization,WTO）杜哈
回合談判陷入僵局後，成為各國之間積極拓展貿易的途徑。請回答下列
問題：
請問一國若參與區域經濟整合，可獲得什麼靜態效果？其福利水準是
否必然提高？若否，取決於什麼因素？（5 分）
承上題，在什麼情況下參與區域經濟整合更可能提高福利？請列舉四
種可能的情況並說明之。（10分）
隨著時間的推移，區域經濟整合會逐漸產生那些動態效果？請列舉四
種可能的動態效果並說明之。（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00013', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-e6f33b51', 'sub-diplomatic-adfe9b2d-02', NULL, 'essay', '根據彈性方法（elasticityapproach）與支用方法（absorptionapproach）的
內容，說明一國貨幣貶值是否會降低該國的經常帳赤字。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00014', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-e6f33b51', 'sub-diplomatic-adfe9b2d-02', NULL, 'single_choice', '根據大麥克指數，2024年1月份臺灣的大麥克價格是新臺幣72元，美國的大麥克價格是美金', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00015', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-e6f33b51', 'sub-diplomatic-adfe9b2d-02', NULL, 'single_choice', '67元。如果真實的匯率是29.88NT$/US$，隱含新臺幣：', '["被高估57.5%", "被高估12.7%", "被低估57.5%", "被低估12.7%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00016', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-e6f33b51', 'sub-diplomatic-adfe9b2d-02', NULL, 'single_choice', '根據Mundell（1963），如果一個國家資本於國際間是完全移動及貨幣當局未從事任何沖銷操作， 則 政策在 匯率制度下有最大的產出效果。', '["貨幣，浮動", "貨幣，固定", "財政，浮動", "財政，固定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL),
  ('diplomatic-adfe9b2d-moex-00017', 'diplomatic-adfe9b2d', 'diplomatic-adfe9b2d-moex-114-e6f33b51', 'sub-diplomatic-adfe9b2d-02', NULL, 'single_choice', '不可能的三位一體（impossibletrinity）是在敘述一個國家不可能同時達成三個目標，這三個目標 不包括下列那一個？', '["資本自由移動", "穩定的匯率", "穩定的通貨膨脹率", "獨立自主的貨幣政策"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:09+00:00", "source_pdf_sha1": "49f91d94d33d", "answer_pdf_sha1": "06702a815132", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-德文組"}'::jsonb, NULL)
